  LoadingScreen, Alert, Button,
} from '../components/UI';
import { formatDate, getErrorMessage } from '../utils/helpers';
import {
  Package, Clock, CheckCircle, XCircle, Flag, AlertTriangle,
  ChevronRight, Search, Filter, TrendingUp, BarChart3,
} from 'lucide-react';
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend,
} from 'recharts';

export default function ManagerDashboard() {
  const [data, setData] = useState({ returns: [], stats: {} });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [riskFilter, setRiskFilter] = useState('');

  useEffect(() => {
    const params = {};
    if (statusFilter) params.status = statusFilter;
    if (riskFilter) params.risk_level = riskFilter;

    returnsService.allReturns(params)
      .then(r => setData(r.data))
      .catch(e => setError(getErrorMessage(e)))
      .finally(() => setLoading(false));
  }, [statusFilter, riskFilter]);

  if (loading) return <LoadingScreen message="Loading dashboard..." />;

  const { returns, stats } = data;
  const filtered = returns.filter(r =>
    !search ||
    r.order_id.toLowerCase().includes(search.toLowerCase()) ||
    r.product_name.toLowerCase().includes(search.toLowerCase()) ||
    r.customer_name.toLowerCase().includes(search.toLowerCase())
  );

  // Chart data
  const pieData = [
    { name: 'Pending', value: stats.pending || 0, color: '#3b82f6' },
    { name: 'Under Review', value: stats.under_review || 0, color: '#f59e0b' },
    { name: 'Approved', value: stats.approved || 0, color: '#10b981' },
    { name: 'Rejected', value: stats.rejected || 0, color: '#ef4444' },
    { name: 'Flagged', value: stats.flagged || 0, color: '#7c3aed' },
  ].filter(d => d.value > 0);

  const riskDist = [
    { label: 'Low (<30%)', count: returns.filter(r => r.risk_score < 0.3).length, fill: '#10b981' },
    { label: 'Medium', count: returns.filter(r => r.risk_score >= 0.3 && r.risk_score < 0.55).length, fill: '#f59e0b' },
    { label: 'High', count: returns.filter(r => r.risk_score >= 0.55 && r.risk_score < 0.75).length, fill: '#ef4444' },
    { label: 'Critical', count: returns.filter(r => r.risk_score >= 0.75).length, fill: '#7c3aed' },
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 py-8 space-y-6 animate-fade-in">
      {/* Header */}
      <div>
        <h1 className="font-display text-2xl font-bold text-slate-900">Manager Dashboard</h1>
        <p className="text-slate-500 text-sm mt-1">AI-powered return request management</p>
      </div>

      {error && <Alert type="error" message={error} onClose={() => setError('')} />}

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-7 gap-4">
        <div className="col-span-2 sm:col-span-4 lg:col-span-2">
          <StatCard icon={Package} label="Total Returns" value={stats.total || 0} color="brand" sub={`${stats.high_risk || 0} high risk`} />
        </div>
        <StatCard icon={Clock} label="Pending" value={stats.pending || 0} color="blue" />
        <StatCard icon={TrendingUp} label="Under Review" value={stats.under_review || 0} color="amber" />
        <StatCard icon={CheckCircle} label="Approved" value={stats.approved || 0} color="green" />
        <StatCard icon={XCircle} label="Rejected" value={stats.rejected || 0} color="red" />
        <StatCard icon={Flag} label="Flagged" value={stats.flagged || 0} color="purple" />
      </div>

      {/* Charts row */}
      {returns.length > 0 && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          <Card className="p-5">
            <div className="flex items-center gap-2 mb-4">
              <BarChart3 className="w-4 h-4 text-slate-400" />
              <h3 className="font-semibold text-slate-700 text-sm">Risk Distribution</h3>
            </div>
            <ResponsiveContainer width="100%" height={160}>
              <BarChart data={riskDist} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                <XAxis dataKey="label" tick={{ fontSize: 10, fill: '#94a3b8' }} />
                <YAxis tick={{ fontSize: 10, fill: '#94a3b8' }} allowDecimals={false} />
                <Tooltip contentStyle={{ fontSize: 11, borderRadius: 8, border: '1px solid #e2e8f0' }} />
                <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                  {riskDist.map((d, i) => <Cell key={i} fill={d.fill} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </Card>

          <Card className="p-5">
            <div className="flex items-center gap-2 mb-4">
              <Flag className="w-4 h-4 text-slate-400" />
              <h3 className="font-semibold text-slate-700 text-sm">Status Breakdown</h3>
            </div>
            <ResponsiveContainer width="100%" height={160}>
              <PieChart>
                <Pie data={pieData} cx="50%" cy="50%" innerRadius={40} outerRadius={65} paddingAngle={3} dataKey="value">
                  {pieData.map((d, i) => <Cell key={i} fill={d.color} />)}
                </Pie>
                <Legend iconType="circle" iconSize={8} wrapperStyle={{ fontSize: 10 }} />
                <Tooltip contentStyle={{ fontSize: 11, borderRadius: 8 }} />
              </PieChart>
            </ResponsiveContainer>
          </Card>
        </div>
      )}

      {/* Filters */}
      <Card className="p-4">
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder="Search by order ID, product, customer..."
              className="w-full pl-9 pr-4 py-2 rounded-xl border border-slate-200 text-sm focus:border-brand-400 focus:outline-none"
            />
          </div>
          <div className="flex items-center gap-2">
            <Filter className="w-4 h-4 text-slate-400 flex-shrink-0" />
            <select
              value={statusFilter}
              onChange={e => setStatusFilter(e.target.value)}
              className="px-3 py-2 rounded-xl border border-slate-200 text-sm focus:border-brand-400 focus:outline-none bg-white"
            >
              <option value="">All Statuses</option>
              <option value="pending">Pending</option>
              <option value="under_review">Under Review</option>
              <option value="approved">Approved</option>
              <option value="rejected">Rejected</option>
              <option value="flagged">Flagged</option>
            </select>
            <select
              value={riskFilter}
              onChange={e => setRiskFilter(e.target.value)}
              className="px-3 py-2 rounded-xl border border-slate-200 text-sm focus:border-brand-400 focus:outline-none bg-white"
            >
              <option value="">All Risk Levels</option>
              <option value="LOW">Low Risk</option>
              <option value="MEDIUM">Medium Risk</option>
              <option value="HIGH">High Risk</option>
              <option value="CRITICAL">Critical</option>
            </select>
          </div>
        </div>
      </Card>

      {/* Table */}
      <Card>
        <div className="px-5 py-4 border-b border-slate-100 flex items-center justify-between">
          <h2 className="font-display font-bold text-slate-900 text-base">Return Requests</h2>
          <span className="text-xs text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
            {filtered.length} shown
          </span>
        </div>

        <Table
          headers={['ID', 'Customer', 'Order ID', 'Product', 'Risk Score', 'Fraud Prob.', 'Status', '']}
          empty="No return requests found."
        >
          {filtered.length > 0 && filtered.map(r => (
            <tr key={r.id} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors group">
              <td className="px-4 py-3 text-xs font-mono text-slate-500">#{r.id}</td>
              <td className="px-4 py-3">
                <p className="text-sm font-semibold text-slate-800">{r.customer_name}</p>
                <p className="text-xs text-slate-400">{r.customer_email}</p>
              </td>
              <td className="px-4 py-3">
                <span className="font-mono text-xs font-medium text-slate-600 bg-slate-100 px-2 py-0.5 rounded">
                  #{r.order_id}
                </span>
              </td>
              <td className="px-4 py-3 text-sm text-slate-700 max-w-[140px] truncate">{r.product_name}</td>
              <td className="px-4 py-3 w-32">
                <RiskBadge score={r.risk_score} />
              </td>
              <td className="px-4 py-3">
                <div className="flex items-center gap-1.5">
                  {r.fraud_probability > 0.6 && <AlertTriangle className="w-3 h-3 text-red-500" />}
                  <span className={`text-xs font-mono font-bold ${r.fraud_probability > 0.6 ? 'text-red-600' : 'text-slate-600'}`}>
                    {Math.round(r.fraud_probability * 100)}%
                  </span>
                </div>
              </td>
              <td className="px-4 py-3"><StatusBadge status={r.status} /></td>
              <td className="px-4 py-3">
                <Link
                  to={`/manager/return/${r.id}`}
                  className="inline-flex items-center gap-1 text-xs font-semibold text-brand-600 hover:text-brand-800 bg-brand-50 hover:bg-brand-100 px-2.5 py-1.5 rounded-lg transition-colors"
                >
                  Review <ChevronRight className="w-3 h-3" />
                </Link>
              </td>
            </tr>
          ))}
        </Table>
      </Card>
    </div>
  );
}
